mapper.select:
select c.*, e.name masterName, (case when now() < begin_date then '未开班' when now() > end_date then '已结课' else '在读中' end) status from clazz c left join emp e on c.master_id = e.id
c.name like concat('%', #{name}, '%')
and c.begin_date >= #{begin}
and c.end_date <= #{end}
order by c.update_time desc
